def Polynomial(xs):
    coeffs = list(xs)
    i = len(coeffs)
    while i > 0:
        if coeffs[i-1]:
            return _Polynomial(slice(coeffs,i))
        i -= 1
    return _Polynomial([])

del _Polynomial

extended +(pol1, pol2):
    c1 = get_coeffs(pol1)
    c2 = get_coeffs(pol2)
    if len(c1) < len(c2):
        c1 += [0]*(len(c2)-len(c1))
    else:
        c2 += [0]*(len(c1)-len(c2))
    c3 = [v[0]+v[1] for v in zip(c1,c2)]
    return Polynomial(c3)

extended *(pol1, pol2):
    c1 = get_coeffs(pol1)
    c2 = get_coeffs(pol2)
    res = [0] * (len(c1)+len(c2)-1)
    for i in range(len(c1)):
        for j in range(len(c2)):
            res[i+j] += c1[i]*c2[j]
    return Polynomial(res)

def enumerate(lst):
    lst = list(lst)
    return [[i, lst[i]] for i in range(len(lst))]

def reverse(lst):
    if not (lst : list):
        raise InvalidArgumentsError
    l = len(lst)
    return [lst[l-1-i] for i in range(l)]

extend str(pol):
    c = get_coeffs(pol)
    if c == []:
        return "0"
    if len(c) == 1:
        return str(c[0])
    p = enumerate(c)
    last_c_str = if c[-1] == 1 then "" else if c[-1] == -1 then "-" else str(c[-1])
    s = last_c_str + if len(c) > 2 then "x^" + str(p[-1][0]) else "x"
    for i in slice(p, -2, None, -1):
        xpow = if i[0] > 1 then "x^" + str(i[0]) else if i[0] == 1 then "x" else  ""
        if not (i[1] : int) and not (i[1] : float) or i[1] > 0:
            s += "+" + (if i[1] == 1 and i[0] then "" else str(i[1])) + xpow
            continue
        if i[1] < 0:
            s += "-" + (if i[1] == -1 and i[0] then "" else str(-i[1])) + xpow
    return s

